const raw = $json || {};

const fromSimple = typeof raw.from === 'string' ? raw.from : '';
const toSimple = Array.isArray(raw.to) ? raw.to.join(',') : '';
const subjectSimple = typeof raw.subject === 'string' ? raw.subject : '';
const snippetSimple = typeof raw.bodyPreview === 'string' ? raw.bodyPreview : '';

const fromRaw = raw.from?.emailAddress?.address || '';
const toRaw = Array.isArray(raw.toRecipients)
  ? raw.toRecipients.map((r) => r?.emailAddress?.address).filter(Boolean).join(',')
  : '';
const subjectRaw = typeof raw.subject === 'string' ? raw.subject : '';
const snippetRaw = typeof raw.bodyPreview === 'string' ? raw.bodyPreview : '';

return [{
  json: {
    messageId: raw.id || '',
    threadId: raw.conversationId || '',
    conversationId: raw.conversationId || '',
    from: fromSimple || fromRaw,
    to: toSimple || toRaw,
    subject: subjectSimple || subjectRaw,
    date: raw.receivedDateTime || '',
    snippet: snippetSimple || snippetRaw,
    text: raw.body?.content || raw.bodyPreview || '',
    html: raw.body?.contentType === 'html' ? (raw.body?.content || '') : '',
    folders: raw.parentFolderId ? [raw.parentFolderId] : [],
    categories: Array.isArray(raw.categories) ? raw.categories : [],
    raw
  }
}];

const normalized = $('Normalize incoming email').item.json || {};
const routeResponse = $json || {};

const statusCode = Number(routeResponse.statusCode || 0) || null;
const hasError = !!routeResponse.error || !!routeResponse.message;
const routeOk = !hasError && (statusCode === null || (statusCode >= 200 && statusCode < 300));

return [{
  json: {
    ok: routeOk,
    action: 'receiveAndRoute',
    messageId: normalized.messageId || null,
    threadId: normalized.threadId || null,
    conversationId: normalized.conversationId || null,
    from: normalized.from || '',
    subject: normalized.subject || '',
    routeResponse
  }
}];
